var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"WATT_BORDER_NULL_ARMED","text":{"KOREA":"일제 사격! 머리의 파손부를 노려라!","JPN":"一斉射撃！　頭の破損部を狙え！","ENG":"All hands, FIRE! Aim for the damaged area on the head!","TWN":"全體射擊！瞄準頭部毀損處！"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"BATTLE_COUNTERISDE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WATT_BORDER_NULL_ARMED","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"GUARD_BORDER_NULL_NULL","text":{"KOREA":"놈이 장벽을 들이받으려 합니다!","JPN":"やつが障壁を突き破ろうとしています！","ENG":"The monster's trying to break through the wall!","TWN":"這傢伙想撞破城牆！"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"BATTLE_COUNTERISDE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GUARD_BORDER_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"WATT_BORDER_NULL_ARMED","text":{"KOREA":"충격 대비! 완충 배리어 전개!","JPN":"衝撃に備えろ！　緩衝バリアを展開！","ENG":"Brace for impact! Activate the shock absorption barrier!","TWN":"預防衝擊！展開緩衝護盾！"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"BATTLE_COUNTERISDE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GUARD_BORDER_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"WATT_BORDER_NULL_ARMED","face":"UNIT_SERIOUS"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L16_1","type":"dialog","speaker":"WATT_BORDER_NULL_ARMED","text":{"KOREA":"다들 괜찮나?","JPN":"みんな大丈夫か？","ENG":"Is everyone all right?","TWN":"大家還好嗎？"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"WATT_BORDER_NULL_ARMED","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"GUARD_BORDER_NULL_NULL","text":{"KOREA":"콜록, 콜록… 괜찮습니다.","JPN":"ゲホ、ゲホ……大丈夫です。","ENG":"*Cough...!* *Cough!* We're good, sir.","TWN":"咳咳，咳咳…… 還好。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GUARD_BORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WATT_BORDER_NULL_ARMED","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"GUARD_BORDER_NULL_NULL","text":{"KOREA":"2종 침식체, 무력화 확인!","JPN":"第2種侵食体、無力化を確認！","ENG":"Category 2 C.O., neutralized!","TWN":"2類侵蝕體，確認失去攻擊力！"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GUARD_BORDER_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"WATT_BORDER_NULL_ARMED","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"WATT_BORDER_NULL_ARMED","text":{"KOREA":"장벽의 상태는?","JPN":"障壁の状態は？","ENG":"What about the wall?","TWN":"城牆的狀態呢？"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GUARD_BORDER_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"WATT_BORDER_NULL_ARMED","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"GUARD_BORDER_NULL_NULL","text":{"KOREA":"일부 손상됐지만 다행히 관통된 곳은 없습니다.","JPN":"一部損傷を受けてますが、幸い貫通したところはありません。","ENG":"It's damaged, but still intact, sir!","TWN":"雖然有部分毀損，但所幸沒有破洞。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GUARD_BORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WATT_BORDER_NULL_ARMED","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"WATT_BORDER_NULL_ARMED","text":{"KOREA":"큭… 크큭…","JPN":"クッ……ククッ……","ENG":"Hah... Hah hah...!","TWN":"咳… 咳咳…"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WATT_BORDER_NULL_ARMED","face":"UNIT_PRIDE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"WATT_BORDER_NULL_ARMED","text":{"KOREA":"모두 잘해 줬다! 우리가 2종 놈을 막았어!","JPN":"みんな、よくやってくれた！　俺たちが第2種の野郎を食い止めたんだ！","ENG":"Well done! We stopped a Category 2 C.O.!","TWN":"大家都做得很好！我們成功擋下2類！"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WATT_BORDER_NULL_ARMED","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"다행이군. 우리가 도착하기 전에 해결된 모양이야.","JPN":"よかったな。私たちが到着する前に解決したようだ。","ENG":"Thank god. They managed to defeat it before we arrived.","TWN":"真是萬幸，似乎在我們抵達前就已經處理完畢。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"아니. 워치에 반응이 와. 침식파가 아직 사라지지 않았어.","JPN":"いや。ウォッチに反応がある。まだ侵食波が消えていない。","ENG":"No. My Watch is still reacting. The Corruption ray hasn't disappeared yet.","TWN":"不對，能量環有反應，侵蝕波還沒有消失。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"WATT_BORDER_NULL_ARMED","text":{"KOREA":"각자 파편 회수하고, 장벽 보수 작업 준비해.","JPN":"各自、破片を回収して障壁を補修する準備をしろ。","ENG":"Collect the rubble and get ready to repair the wall.","TWN":"大家回收碎片，準備維修城牆。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WATT_BORDER_NULL_ARMED","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"WATT_BORDER_NULL_ARMED","text":{"KOREA":"오늘 저녁은 든든하게 먹자고.","JPN":"今日の夕飯はいっぱい食べようぜ。","ENG":"But tonight, we feast!","TWN":"今晚要吃飽點！"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WATT_BORDER_NULL_ARMED","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"GUARD_BORDER_NULL_WATCHER","text":{"KOREA":"<color=#ffd34c>어라? 2종 침식체 신호가 다시 잡히고 있습니다.</color>","JPN":"<color=#ffd34c>おや？　第2種侵食体の信号がまた現れました。</color>","ENG":"<color=#ffd34c>Huh? The Category 2 C.O.'s signal is picking up again.</color>","TWN":"<color=#ffd34c>嗯？又收到2類侵蝕體的訊號。</color>"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WATT_BORDER_NULL_ARMED","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L33_1","type":"dialog","speaker":"WATT_BORDER_NULL_ARMED","text":{"KOREA":"그게 무슨 소리야? 방금 처리했잖아?","JPN":"どういうことだ？　今やっつけただろ？","ENG":"What are you talking about? We just killed it!","TWN":"什麼意思？剛才不是都已經處理完畢嗎?"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WATT_BORDER_NULL_ARMED","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"GUARD_BORDER_NULL_WATCHER","text":{"KOREA":"<color=#ffd34c>아뇨! 다른 곳입니다!</color>","JPN":"<color=#ffd34c>いいえ、別のところです！</color>","ENG":"<color=#ffd34c>No! It's coming from somewhere else!</color>","TWN":"<color=#ffd34c>不！是別的地方！</color>"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WATT_BORDER_NULL_ARMED","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L36_1","type":"dialog","speaker":"GUARD_BORDER_NULL_WATCHER","text":{"KOREA":"<color=#ffd34c>게다가 하나가 아니에요! 신호가 계속 늘어나고 있습니다!</color>","JPN":"<color=#ffd34c>しかも一つじゃありません！　信号が増え続けています！</color>","ENG":"<color=#ffd34c>And it's not just one! There are multiple signals showing up!</color>","TWN":"<color=#ffd34c>而且不止一個！訊號一直在增加！</color>"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WATT_BORDER_NULL_ARMED","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"GUARD_BORDER_NULL_A","text":{"KOREA":"방금 진동 느꼈어?","JPN":"今の振動、感じたか？","ENG":"Did you feel that vibration just now?","TWN":"你剛有感覺到地震嗎？"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GUARD_BORDER_NULL_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GUARD_BORDER_NULL_B","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"GUARD_BORDER_NULL_B","text":{"KOREA":"…진짜야? 2종이 여럿 나타난 적은 지금까지 없었는데?","JPN":"……マジかよ。第2種が複数現れるなんて、今までなかったのに。","ENG":"For real? But there's never been more than one Category 2 C.O. showing up before!","TWN":"…真的嗎？目前爲止還沒一次出現很多2類過呢？"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GUARD_BORDER_NULL_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GUARD_BORDER_NULL_B","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"WATT_BORDER_NULL_ARMED","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WATT_BORDER_NULL_ARMED","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_MONSTER_MOVEMENT_03"},{"id":"L50_1","type":"dialog","speaker":"WATT_BORDER_NULL_ARMED","text":{"KOREA":"전원 위치 사수! 2파에 대비해라!","JPN":"全員、位置を守れ！　第2波に備えろ！","ENG":"Everyone, get into position! Get ready for wave 2!","TWN":"大家各就各位！預備進入第2波！"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WATT_BORDER_NULL_ARMED","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L2_1","type":"dialog","speaker":"GUARD_BORDER_NULL_WATCHER","text":{"KOREA":"<color=#ffd34c>점점 가까워집니다! 오백 미터!</color>","JPN":"<color=#ffd34c>だんだん近づいてきています！　500メートル！</color>","ENG":"<color=#ffd34c>They're closing up on us! 500m!</color>","TWN":"<color=#ffd34c>接近中！500公尺！</color>"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WATT_BORDER_NULL_ARMED","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L3_1","type":"dialog","speaker":"GUARD_BORDER_NULL_WATCHER","text":{"KOREA":"<color=#ffd34c>삼백 미터! 백 미터……!</color>","JPN":"<color=#ffd34c>300メートル！　100メートル……！</color>","ENG":"<color=#ffd34c>300m! 100m...!</color>","TWN":"<color=#ffd34c>300公尺！100公尺……！</color>"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WATT_BORDER_NULL_ARMED","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"GUARD_BORDER_NULL_A","text":{"KOREA":"어이, 뭐가 보여?","JPN":"おい、何か見えるか？","ENG":"Hey, do you see anything?","TWN":"喂，你有看到什麼嗎？"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GUARD_BORDER_NULL_A","face":"UNIT_SURPRISE"},"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"GUARD_BORDER_NULL_B","text":{"KOREA":"아니, 아무것도 안 보이는데?","JPN":"いや、何も見えないぞ。","ENG":"No, I can’t see a thing.","TWN":"沒有，什麼都沒看到。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GUARD_BORDER_NULL_A","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"GUARD_BORDER_NULL_B","face":"UNIT_SURPRISE"}}}},{"id":"L7_1","type":"dialog","speaker":"GUARD_BORDER_NULL_A","text":{"KOREA":"그러면 탐지기가 고장 난 게 아닐까?","JPN":"だったら探知機が故障したんじゃないのか？","ENG":"Maybe the detector malfunctioned?","TWN":"探測器是不是壞啦？"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GUARD_BORDER_NULL_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GUARD_BORDER_NULL_B","face":"UNIT_SURPRISE"}}}},{"id":"L9_1","type":"dialog","speaker":"GUARD_BORDER_NULL_A","text":{"KOREA":"으윽! 방금 뭐였지?","JPN":"ううっ！　今のはなんだ？","ENG":"Whoa! What was that?","TWN":"唔！剛剛是怎麼回事？"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GUARD_BORDER_NULL_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GUARD_BORDER_NULL_B","face":"UNIT_SURPRISE"}}}},{"id":"L10_1","type":"dialog","speaker":"GUARD_BORDER_NULL_B","text":{"KOREA":"장벽이 흔들린다! 뭐라도 붙잡아!","JPN":"障壁が揺れてる！　なんでもいいから掴め！","ENG":"The wall's shaking! Grab onto something!","TWN":"城牆在晃動！大家找東西抓著！"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GUARD_BORDER_NULL_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GUARD_BORDER_NULL_B","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"WATT_BORDER_NULL_ARMED","text":{"KOREA":"큭……! 침식체가 안 보인다는 건 설마?!","JPN":"くっ……！　侵食体が見えないということは、まさか！？","ENG":"Krgh...! If we can't see the C.O.s, then does that mean...?!","TWN":"咳……！難道是看不見的侵蝕體？！"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WATT_BORDER_NULL_ARMED","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"놈들이 땅 밑에서 장벽을 부수려는 거야.","JPN":"やつらは地面の下から障壁を壊すつもりよ。","ENG":"They're trying to break the wall from underneath.","TWN":"它們想從地底下破壞城牆。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"장벽이 지하까지 막고 있는 건가?","JPN":"障壁が地下まで伸びているのか？","ENG":"Does the wall go deep underground as well?","TWN":"城牆有連到地底下嗎？"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"장벽이 세워진 뒤로 수 차례의 지각변동이 있었어.","JPN":"障壁が立てられて以来、数回の地殻変動があったんだ。","ENG":"There have been several tectonic shifts after the wall was built.","TWN":"城牆建好後，發生過好幾次地殼變動。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"셔우드 외성의 장벽 중 절반 이상이 아래에 묻혀 있는 셈이지.","JPN":"シャーウッド外郭の障壁の中で、半分以上が地面に埋もれているというわけ。","ENG":"In other words, more than half of outer castle Sherwood's wall in buried underground.","TWN":"因此休烏特外城的城牆，有一半以上都被埋在地底下。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"덕분에 당장은 놈들이 외성 안으로 들어오는 걸 막고 있지만…","JPN":"おかげで今はやつらが外郭の中に入って来るのを防いでるけど……","ENG":"Thanks to that, we're able to stop them from infiltrating the castle at the moment...","TWN":"幸好因為這樣，城牆目前還能擋住它們…   "},"stage":{"bg":"NOMAD_VILLAGE","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"지금 우리가 가진 무기로는 땅 밑에 숨은 녀석들을 처리할 방법이 없어.","JPN":"今私たちが持っている武器では地面の下に隠れているやつらを処理する方法がない。","ENG":"But we don't have any weapons that can kill that thing underground.","TWN":"但光靠我們現有的武器，根本就沒辦法對付那些躲在地底下的傢伙。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"이대로는 속수무책으로 당하고 말 거야.","JPN":"このままでは何もできないままやられてしまうはずよ。","ENG":"We'll be sitting ducks here if we don't do anything.","TWN":"這樣下去，最後也只能坐以待斃。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"방법이라면 있다.","JPN":"方法ならある。","ENG":"There might be a way.","TWN":"我有辦法。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"대응할 시간이 그렇게 많지 않아. 확실해?","JPN":"時間はあまり多くない。確かなの？","ENG":"We don't have much time. Are you sure?","TWN":"我們應對的時間不多，你確定嗎？"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"확실하다. 하지만 나 혼자서 실행에 옮기는 건 불가능해.","JPN":"確かだ。だが、私一人では無理だ。","ENG":"I'm certain. But I won't be able to do it alone.","TWN":"確定，但是光靠我一個人是辦不到的。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"WATT_BORDER_NULL_ARMED","text":{"KOREA":"예? 쐐기 대포를 말입니까?","JPN":"は？　くさび大砲をですか？","ENG":"Huh? The Ironshot Cannon?","TWN":"什麼？楔子大砲嗎？"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WATT_BORDER_NULL_ARMED","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"그래. 쐐기창이라면 놈들이 파고든 곳까지 닿을 수 있다.","JPN":"そう。くさび槍ならやつらが入り込んだところまで届くはず。","ENG":"Yes. The Cannon has enough power to reach them underground.","TWN":"對，楔子砲能打到那些傢伙所在的地方。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WATT_BORDER_NULL_ARMED","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"WATT_BORDER_NULL_ARMED","text":{"KOREA":"쐐기창을 사용한다면…… 타격은 줄 수 있겠군요.","JPN":"くさび槍を使えば……ダメージは与えられそうですね。","ENG":"And using the Ironshot Spear... we’ll be able to hit them.","TWN":"使用楔子砲……確實是能打到它們。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WATT_BORDER_NULL_ARMED","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"WATT_BORDER_NULL_ARMED","text":{"KOREA":"하지만 어디에 있는지도 모르는 녀석들의 약점을 노리긴 힘들 겁니다.","JPN":"ですが、どこにいるのかわからないやつの弱点を突くことは難しいはずです。","ENG":"Only problem is that we don't know where they are, so aiming for their weak points is going to be difficult.","TWN":"但又不知道它們的確切位置，很難命中紅心。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WATT_BORDER_NULL_ARMED","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"침식체는 단순해. 위쪽에서 공격을 받는 순간, 공격한 상대를 찾아 위로 튀어나올 거다.","JPN":"侵食体は単純だ。上から攻撃を受けた瞬間、攻撃した相手を探して上に飛び出してくるはずだ。","ENG":"C.O.s are simple creatures. The moment they're attacked from above, they'll come up to the surface to find whatever attacked them.","TWN":"侵蝕體頭腦簡單，受到來自上方的攻擊時，就會立刻找到攻擊方向上跳。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"그 때를 노려 한 마리씩 집중적으로 공략하면 놈을 처치할 수 있어.","JPN":"その時を狙って一匹ずつ集中して攻略すれば処理できる。","ENG":"That's when we fight. Focusing them down one by one.","TWN":"我們再趁機一隻一隻集中攻擊，就能把那些傢伙處理掉。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"WATT_BORDER_NULL_ARMED","text":{"KOREA":"대장, 저 자의 작전은 실전성이 전혀 입증되지 않았습니다.","JPN":"隊長、あの者の作戦は実戦性がまったく立証されていません。","ENG":"Captain. We have no way of knowing if this man's plan will actually work.","TWN":"隊長，他說的方法完全沒經過驗證，"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WATT_BORDER_NULL_ARMED","face":"UNIT_SERIOUS"}}}},{"id":"L37_1","type":"dialog","speaker":"WATT_BORDER_NULL_ARMED","text":{"KOREA":"저희가 시간을 버는 동안 주민들을 대피시키는 편이 나을지도 모릅니다.","JPN":"俺らが時間を稼いでる間に、住民を避難させた方がいいかもしれませんよ。","ENG":"It might be best to evacuate the villagers while we buy you some time.","TWN":"倒不如爭取時間引導村民避難。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WATT_BORDER_NULL_ARMED","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"우리가 외성을 포기하면 놈들은 도시까지 노릴 거야. 그런 건 해결책이 아니야.","JPN":"私たちが外郭を放棄したら、やつらは都市まで狙うはずよ。そんなのは解決策じゃない。","ENG":"If we let them pass the outer castle they'll reach for the city. Running away isn't going to solve our problem.","TWN":"如果我們放棄外城，都市就會成為它們下一個目標，那不是解決之道。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WATT_BORDER_NULL_ARMED","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"WATT_BORDER_NULL_ARMED","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WATT_BORDER_NULL_ARMED","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"WATT_BORDER_NULL_ARMED","text":{"KOREA":"알겠습니다. 그럼 대포 통제권은 잠시 저 자에게 넘기도록 하죠.","JPN":"わかりました。それでは大砲の統制権はしばらくあの者に預けましょう。","ENG":"Yes, ma'am. Then I will grant him temporary authorization to use the cannon.","TWN":"好吧，那就把大砲的控制權暫時交給他吧。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WATT_BORDER_NULL_ARMED","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"아니. 대포를 쏘는 건 와트, 자네가 맡아줬으면 해.","JPN":"いや。大砲を撃つのはワット、君がやってくれ。","ENG":"No. You will be shooting the cannon, Watt. I want you to do it.","TWN":"不，我希望是由你來負責發射大砲。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"엘라 대장이 수비대에 자네만큼 병기를 잘 다루는 기술자가 없다고 하더군.","JPN":"エラ隊長がこの守備隊に兵器の扱いにおいて君の右に出る者はいないと言っていた。","ENG":"Captain Ella's told me that there's no technician in the village who can handle weapons better than you.","TWN":"艾拉隊長說你是整個護衛隊裡，最會操作兵器的技師。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"WATT_BORDER_NULL_ARMED","text":{"KOREA":"쳇, 입에 발린 소리나 늘어놓긴.","JPN":"ちっ、お世辞をならべやがって。","ENG":"Tch! You and your sly tongue.","TWN":"嘖，亂說話。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WATT_BORDER_NULL_ARMED","face":"UNIT_HATE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"WATT_BORDER_NULL_ARMED","text":{"KOREA":"그럼 그쪽은 뒤에서 손 놓고 구경이나 할 셈인가?","JPN":"じゃあ、あんたは後ろで何もせずに見学でもするつもりか？","ENG":"Then what about you? Are you going to stand back and just watch?","TWN":"那你呢？你負責在一旁看戲嗎？"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WATT_BORDER_NULL_ARMED","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"나는 엘라 대장과 함께 장벽 밖으로 나가겠다.","JPN":"私はエラ隊長と一緒に障壁の外に出る。","ENG":"Captain Ella and I will head outside of the wall.","TWN":"我要和艾拉隊長一起出城。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_LAUGH"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"WATT_BORDER_NULL_ARMED","text":{"KOREA":"뭐?! 대장이야 그렇다 쳐도 당신은 카운터도 아니잖아!","JPN":"何！？　隊長はともかく、あんたはカウンターでもねえんだろ！","ENG":"What?! I can understand the Captain, but you're not even a Counter!","TWN":"什麼？！隊長我話說，但你又不是制裁者！"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WATT_BORDER_NULL_ARMED","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"난 그렇다 치는 거냐?","JPN":"私はともかくなのか？","ENG":"What's that supposed to mean, huh?","TWN":"你是想說什麼？"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"WATT_BORDER_NULL_ARMED","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"WATT_BORDER_NULL_ARMED","text":{"KOREA":"죄, 죄송합니다. 그런 뜻이 아니라…","JPN":"も、申し訳ありません。そういう意味では……","ENG":"M-my apologies. What I meant was that...","TWN":"抱…抱歉，我不是那個意思…"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"WATT_BORDER_NULL_ARMED","face":"UNIT_SURPRISE"}}}},{"id":"L1_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"농담이야.","JPN":"冗談よ。","ENG":"I'm kidding.","TWN":"開玩笑的。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WATT_BORDER_NULL_ARMED","face":"UNIT_SURPRISE"}}}},{"id":"L2_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"침식체를 지상으로 유인하더라도, 장벽 위에서 싸우면 시선을 끌지 못해.","JPN":"侵食体を地上へおびき寄せるとしても、障壁の上で戦うと注目を集められない。","ENG":"Even if we are successful in luring out the C.O.s to the surface, fighting on the wall won't attract their attention.","TWN":"就算把侵蝕體引出地面，在城牆上作戰也無法吸引它們的注意。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WATT_BORDER_NULL_ARMED","face":"UNIT_SURPRISE"}}}},{"id":"L3_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"하지만 큐리안 대원에겐 병기마가 있으니 충분히 놈들을 따돌릴 수 있어.","JPN":"だけど、キュリアン隊員には兵器馬があるから十分やつらをまくことができる。","ENG":"But since Curian has an Armored Horse, that'll be enough to keep them off our tail.","TWN":"不過庫里安隊員有戰馬，完全可以甩掉它們。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WATT_BORDER_NULL_ARMED","face":"UNIT_SURPRISE"}}}},{"id":"L4_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"놈들의 시선을 끌어서 다시 땅 속으로 들어가지 못하게 하는 거지.","JPN":"やつらの目を引いて再び地中に入れないようにするんだ。","ENG":"Our job will be to distract them so they don't go back underground.","TWN":"也就是吸引它們的注意，讓它們不再進到地底下。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WATT_BORDER_NULL_ARMED","face":"UNIT_SURPRISE"}}}},{"id":"L5_1","type":"dialog","speaker":"WATT_BORDER_NULL_ARMED","text":{"KOREA":"……거 진짜 목숨 내놓고 하는 짓이 되겠군요.","JPN":"……まさに命懸けですね。","ENG":"...So you're really going to risk your life.","TWN":"……那真的是拿命在拚呢。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WATT_BORDER_NULL_ARMED","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"그러니까 빗나가지 않게 잘 쏴.","JPN":"だから外れないようにちゃんと撃って。","ENG":"Yeah, so don't miss, okay?","TWN":"所以你千萬不能射偏。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WATT_BORDER_NULL_ARMED","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"WATT_BORDER_NULL_ARMED","text":{"KOREA":"죽지나 마십쇼, 두 분 다.","JPN":"死なないでくださいよ、二人とも。","ENG":"Both of you, don't die.","TWN":"二位保重，千萬要活著回來。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WATT_BORDER_NULL_ARMED","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"WATT_BORDER_NULL_ARMED","text":{"KOREA":"사격조는 위치 사수! 포격 훈련 받은 적 있는 녀석들은 다들 대포로 간다! 움직여!","JPN":"射撃組は位置を守れ！　砲撃の訓練を受けたことのあるやつらは全員大砲があるとろこに行くんだ！　行動開始！","ENG":"Gunners, get into position! Everyone with cannon training, head over there! Move!","TWN":"射擊組堅持住！受過砲擊訓練的人全都到大砲那！開始動作！"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WATT_BORDER_NULL_ARMED","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"}]`);export{e as default};